[BusinessEvents(classStr(SalesPackingSlipBusinessEventContract), "SalesPackingSlipPosted", "Fires when a Sales Order Packing Slip is posted", ModuleAxapta::SalesOrder)]
public final class SalesPackingSlipBusinessEvent extends BusinessEventsBase
{
    private CustPackingSlipJour packingSlipJour;

}

Method.Source:
private CustPackingSlipJour parmPackingSlipJour(CustPackingSlipJour _packingSlipJour = packingSlipJour)
{
    packingSlipJour = _packingSlipJour;
    return packingSlipJour;
}

public static SalesPackingSlipBusinessEvent newFromCustPackingSlipJour(CustPackingSlipJour _packingSlipJour)
{
    SalesPackingSlipBusinessEvent businessEvent = new SalesPackingSlipBusinessEvent();
    businessEvent.parmPackingSlipJour(_packingSlipJour);
    return businessEvent;
}
